/* adm-master-account-sql-oracle.xml selectAccount */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT '0' AS CHK ,A.ACKEY ,(SELECT COUNT(1) FROM TADMIN_MST_ACXCT C WHERE C.ACKEY = A.ACKEY AND C.OWKEY = A.OWKEY) AS DTLCNT ,A.ACTYPE ,A.ACNM ,A.REGNO ,A.BIZTYPE ,A.BIZCTG ,A.TEL1 ,A.TEL2 ,A.FAX ,A.CONTACT ,A.CEO ,A.UDF1 ,A.UDF2 ,A.UDF3 ,A.REPACKEY , (SELECT ACNM FROM TADMIN_MST_AC AC WHERE AC.OWKEY = A.OWKEY AND AC.ACKEY = A.REP_ACKEY) AS REPACNM ,A.REPACTYPE ,A.ADDRID ,A.CLOSDATE ,A.INSERTURKEY ,A.UPDATEURKEY ,A.INSERTDATE ,A.UPDATEDATE ,A.DELYN ,'YESORNO' || ';' || COALESCE(A.DELYN, 'N') AS DELYN_DESC ,A.REGDATE ,A.EMAIL ,A.ASNUSEYN ,A.ADDR1 ,A.ADDR2 ,A.ZIPCD ,A.PLTMAXRT ,A.PNLTYALWNRT ,A.PNLTYAPLYYN ,A.STARTDATE AS ACSTARTDATE ,A.ENDDATE AS ACENDDATE ,A.SCMCK ,A.SCMURKEY ,A.OWKEY ,A.IFYN ,C.OWNM ,A.ACTYPE2 ,A.ACTYPEDT ,A.ACGRADE FROM TADMIN_MST_AC A INNER JOIN TADMIN_MST_OW C ON A.OWKEY = C.OWKEY
#{SEARCH_CONDITION}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY A.UPDATEDATE DESC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

