	(
        OWKEY
        ,ACKEY 
        ,ACTYPE 
        ,ACNM
        ,REGNO
		,BIZTYPE
		,BIZCTG
        ,CNTRYCD
        ,ADDR1
        ,ADDR2
        ,ZIPCD
        ,TEL1 
        ,TEL2 
        ,FAX 
        ,CONTACT 
        ,CEO 
       	,UDF1
        ,UDF2
        ,UDF3
        ,REPACKEY
        ,REPACTYPE
        ,ADDRID
        ,REGDATE
        ,EMAIL
        ,ASNUSEYN
		,ACTYPE2
		,ACTYPEDT
        ,CLOSDATE
        ,INSERTDATE 
        ,INSERTURKEY 
        ,UPDATEDATE 
        ,UPDATEURKEY
	) VALUES (
		 #{owkey}
        ,#{ackey}
        ,#{actype}
        ,#{acnm}
        ,#{regno}
        ,#{biztype}
        ,#{bizctg}
		,'KOR'		       
        ,#{addr1}
