        ,#{zipcd}
        ,#{tel1}
        ,#{tel2}
        ,#{fax}
        ,#{contact}
        ,#{ceo}
        ,#{udf1}
        ,#{udf2}
        ,#{udf3}
        ,#{repackey}
        ,#{repactype}
        ,#{addrid}
        ,#{regdate}
        ,#{email}
        ,#{asnuseyn}
		,#{actype2}
		,#{actypedt}
        ,#{closdate}
