/* adm-master-account-sql-oracle.xml  updateTAdminMstAc */
	UPDATE TADMIN_MST_AC
	   SET   ADDR1       		= #{addr1}
			,ADDR2       	= #{addr2}
			,ZIPCD       	 	= #{zipcd}

	        ,ACTYPE				= #{actype}
	        ,ACNM         	= #{acnm}
	        ,REGNO       		= #{regno}
	        ,BIZTYPE   		= #{biztype}
	        ,BIZCTG			= #{bizctg}
	        ,CNTRYCD    	= #{cntrycd}
	        ,TEL1           	= #{tel1}       
	        ,TEL2           	= #{tel2}       
	        ,FAX            	= #{fax}        
	        ,CONTACT        	= #{contact}    
	        ,CEO            	= #{ceo} 
	        ,UDF1            	= #{udf1} 
	        ,UDF2            	= #{udf2} 
	        ,UDF3            	= #{udf3}
	        ,REPACKEY			= #{repackey}
	        ,REPACTYPE			= #{repactype}
	        ,ADDRID				= #{addrid}
	        ,REGDATE 		   	= #{regdate}
	        ,EMAIL				= #{email}
	        ,ASNUSEYN			= #{asnuseyn}
	     	,ACTYPE2			= #{actype2}
	     	,ACTYPEDT   		= #{actypedt}
	        ,CLOSDATE    	= #{closdate}
			,DELYN    			= #{delyn}

	        ,UPDATEDATE     	= #{sysdate}
	        ,UPDATEURKEY    	= #{surkey}
	 WHERE ACKEY = #{ackey}
	   AND OWKEY = #{owkey}

/* adm-master-account-sql-oracle.xml  deleteTAdminMstAc */
	UPDATE
		TADMIN_MST_AC
	SET
		DELYN = 'Y'
	 	,CLOSDATE  = #{closdate}
        ,UPDATEDATE   = #{sysdate}
        ,UPDATEURKEY  = #{surkey}
	WHERE 
		ACKEY = #{ackey}
	AND OWKEY = #{owkey}

