/* adm-master-account-sql-oracle.xml  selectRepAccountCount */
		SELECT	COUNT(1)  
		  FROM	TADMIN_MST_AC
		  WHERE REPACTYPE = '1'
		  AND	ACKEY = REPACKEY
		   AND OWKEY = #{owkey} 



		            AND ACKEY = #{searchValue}


		   			AND (ACKEY LIKE '%' || #{searchValue} || '%' OR ACNM LIKE '%' || #{searchValue} || '%')

/* adm-master-account-sql-oracle.xml selectRepAccount */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT ACKEY ,ACTYPE ,'ACTYPE' ||';'|| ACTYPE AS ACTYPE_DESC ,ACNM ,REPACKEY ,REPACTYPE ,'REP_ACTYPE' ||';'|| REPACTYPE as REP_ACTYPE_DESC ,OWKEY FROM TADMIN_MST_AC WHERE REPACTYPE = '1' AND ACKEY = REPACKEY AND OWKEY = #{owkey}
AND ACKEY = #{searchValue}
AND (ACKEY LIKE '%' || #{searchValue} || '%' OR ACNM LIKE '%' || #{searchValue} || '%')
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY UPDATEDATE DESC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}
